function PasswordField({
  id,
  label,
  value,
  onChange,
  autoComplete,
  rightSlot,
}) {
  const [visible, setVisible] = useState(false)

  return (
    <div className='flex flex-col gap-1'>
      <div className='flex items-center justify-between'>
        <label
          htmlFor={id}
          className='text-xs font-semibold tracking-widest uppercase text-text-muted'
        >
          {label}
        </label>
        {rightSlot}
      </div>
      <div className='relative'>
        <input
          id={id}
          type={visible ? 'text' : 'password'}
          required
          minLength={6}
          autoComplete={autoComplete}
          value={value}
          onChange={onChange}
          className='w-full border-2 border-primary-100 outline-none focus:border-primary rounded p-2.5 pr-10 text-sm bg-surface'
        />
        <button
          type='button'
          onClick={() => setVisible((v) => !v)}
          aria-label={visible ? 'Hide password' : 'Show password'}
          className='absolute right-2 top-1/2 -translate-y-1/2 text-text/50 hover:text-text transition-colors duration-300 cursor-pointer'
        >
          <EyeIcon open={visible} />
        </button>
      </div>
    </div>
  )
}

